 89→export default function SketchToolbar() {
 90→  const { activeTool, activeView, showGrid, snapEnabled, workspaceMode, activeSheetId, dispatch: editorDispatch } = useSketchEditor();
 91→  const { project, canUndo, canRedo, dispatch } = useSketch();
 92→  const { handleNew, handleSave, handleLoadClick } = useSketchProject();
 93→  const [showAddViewport, setShowAddViewport] = useState(false);
 94→
 95→  const isSheetMode = workspaceMode === 'sheet';
 96→  const sheet = isSheetMode
 97→    ? (project.sheets || []).find((s) => s.id === activeSheetId)
 98→    : null;
 99→
100→  const handleUndo = () => {
101→    if (!canUndo) return;
102→    dispatch({ type: 'UNDO' });
103→    editorDispatch({ type: 'DESELECT' });
104→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Undid last change.' });
105→  };
106→
107→  const handleRedo = () => {
108→    if (!canRedo) return;
109→    dispatch({ type: 'REDO' });
110→    editorDispatch({ type: 'DESELECT' });
111→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Redid last change.' });
112→  };
113→
114→  const handleBackToModel = () => {
115→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
116→  };
117→
118→  const handleAddViewport = (sourceView) => {
119→    if (!sheet) return;
120→    const viewport = createSheetViewport(sourceView, null, {
121→      scale: 5,
122→    });
123→    dispatch({ type: 'SKETCH_SHEET_VIEWPORT_ADD', sheetId: sheet.id, viewport });
124→    setShowAddViewport(false);
125→  };
126→
127→  const handleExportPdf = async () => {
128→    if (!sheet) return;
129→    try {
130→      await exportActiveSheetAsPdf(sheet.title || 'sketch-sheet', sheet.paperSize);
131→    } catch (err) {
132→      console.error('PDF export failed:', err);
133→    }
134→  };
135→
136→  const handleExportPng = async () => {
137→    if (!sheet) return;
138→    try {
139→      await exportActiveSheetAsPng(sheet.title || 'sketch-sheet');
140→    } catch (err) {
141→      console.error('PNG export failed:', err);
142→    }
143→  };
144→
145→  return (
146→    <div className={styles.toolbar}>
147→      {/* Undo/Redo group */}
148→      <div className={styles.group}>
149→        <button className={styles.btn} onClick={handleUndo} disabled={!canUndo} aria-label="Undo" title="Undo (Ctrl+Z)">
150→          <svg viewBox="0 0 18 18" className={styles.icon}>
151→            <path d="M6 7l-4 3 4 3" fill="none" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round" />
152→            <path d="M2 10h10a4 4 0 1 1 0 8H8" fill="none" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" />
153→          </svg>
154→        </button>
155→        <button className={styles.btn} onClick={handleRedo} disabled={!canRedo} aria-label="Redo" title="Redo (Ctrl+Shift+Z)">
156→          <svg viewBox="0 0 18 18" className={styles.icon}>
157→            <path d="M12 7l4 3-4 3" fill="none" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round" />
158→            <path d="M16 10H6a4 4 0 1 0 0 8h4" fill="none" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" />
159→          </svg>
160→        </button>
161→      </div>
162→
163→      <div className={styles.divider} />
164→
165→      {/* Project actions */}
166→      <div className={styles.group}>
167→        <span className={styles.groupLabel}>Project</span>
168→        <button className={styles.btn} onClick={handleNew} aria-label="New Project" title="New Project">
169→          <svg viewBox="0 0 18 18" className={styles.icon}>
170→            <path d="M4 2h7l4 4v10a1 1 0 0 1-1 1H4a1 1 0 0 1-1-1V3a1 1 0 0 1 1-1z" fill="none" stroke="currentColor" strokeWidth="1.4" strokeLinejoin="round" />
171→            <path d="M11 2v4h4" fill="none" stroke="currentColor" strokeWidth="1.4" strokeLinejoin="round" />
172→          </svg>
173→        </button>
174→        <button className={styles.btn} onClick={handleSave} aria-label="Save Project" title="Save Project (Ctrl+S)">
175→          <svg viewBox="0 0 18 18" className={styles.icon}>
176→            <path d="M14 16H4a1 1 0 0 1-1-1V3a1 1 0 0 1 1-1h8l4 4v9a1 1 0 0 1-1 1z" fill="none" stroke="currentColor" strokeWidth="1.4" strokeLinejoin="round" />
177→            <path d="M6 2v5h6V2" fill="none" stroke="currentColor" strokeWidth="1.2" />
178→            <path d="M6 16v-5h6v5" fill="none" stroke="currentColor" strokeWidth="1.2" />
179→          </svg>
180→        </button>
181→        <button className={styles.btn} onClick={handleLoadClick} aria-label="Open Project" title="Open Project">
182→          <svg viewBox="0 0 18 18" className={styles.icon}>
183→            <path d="M2 6V4a1 1 0 0 1 1-1h4l2 2h6a1 1 0 0 1 1 1v1" fill="none" stroke="currentColor" strokeWidth="1.4" strokeLinejoin="round" />
184→            <path d="M2 6h14l-2 9H4z" fill="none" stroke="currentColor" strokeWidth="1.4" strokeLinejoin="round" />
185→          </svg>
186→        </button>
187→      </div>
188→
189→      <div className={styles.divider} />
190→
191→      {isSheetMode ? (
192→        <>
193→          {/* Back to Model */}
194→          <div className={styles.group}>
195→            <button className={styles.btn} onClick={handleBackToModel} aria-label="Back to Model" title="Back to Model">
196→              <svg viewBox="0 0 18 18" className={styles.icon}>
197→                <path d="M10 4L5 9l5 5" fill="none" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" strokeLinejoin="round" />
198→              </svg>
199→            </button>
200→            <span className={styles.groupLabel}>Model</span>
201→          </div>
202→
203→          <div className={styles.divider} />
204→
205→          {/* Add Viewport dropdown */}
206→          <div className={styles.group} style={{ position: 'relative' }}>
207→            <span className={styles.groupLabel}>Viewport</span>
208→            <button
209→              className={styles.btn}
