211→              aria-label="Add Viewport"
212→              title="Add Viewport"
213→            >
214→              <svg viewBox="0 0 18 18" className={styles.icon}>
215→                <path d="M9 3v12M3 9h12" fill="none" stroke="currentColor" strokeWidth="1.4" strokeLinecap="round" />
216→              </svg>
217→            </button>
218→            {showAddViewport && (
219→              <div className={styles.dropdown}>
220→                {viewportSourceOptions.map((opt) => (
221→                  <button
222→                    key={opt.value}
