224→                    onClick={() => handleAddViewport(opt.value)}
225→                  >
226→                    {opt.label}
227→                  </button>
228→                ))}
229→              </div>
230→            )}
231→          </div>
232→
233→          <div className={styles.spacer} />
234→
235→          {/* Export */}
236→          <div className={styles.group}>
237→            <span className={styles.groupLabel}>Export</span>
238→            <button className={styles.btn} onClick={handleExportPdf} disabled={!sheet} aria-label="Export PDF" title="Export PDF">
239→              PDF
240→            </button>
241→            <button className={styles.btn} onClick={handleExportPng} disabled={!sheet} aria-label="Export PNG" title="Export PNG">
242→              PNG
243→            </button>
244→          </div>
245→        </>
246→      ) : (
247→        <>
248→          {/* Tool palette */}
249→          <div className={styles.toolPalette}>
250→            <span className={styles.groupLabel}>Parts</span>
251→            {toolItems.map(({ tool, label, shortcut, icon }) => (
