253→                key={tool}
254→                className={activeTool === tool ? styles.toolBtnActive : styles.toolBtn}
255→                onClick={() => editorDispatch({ type: 'SET_TOOL', tool })}
256→                aria-label={label}
257→                title={`${label} (${shortcut})`}
258→              >
259→                <ToolIcon icon={icon} />
