268→            <span className={styles.groupLabel}>View</span>
269→            {viewItems.map(({ view, label }) => (
270→              <button
271→                key={view}
272→                className={activeView === view ? styles.toolBtnActive : styles.toolBtn}
273→                onClick={() => editorDispatch({ type: 'SET_VIEW', view })}
274→                aria-label={`${label} view`}
275→                title={`${label} view`}
276→              >
277→                {label}
278→              </button>
279→            ))}
280→          </div>
281→
282→          <div className={styles.divider} />
283→
284→          {/* Display toggles */}
285→          <div className={styles.group}>
286→            <span className={styles.groupLabel}>Display</span>
287→            <button
288→              className={`${styles.toggleBtn} ${showGrid ? styles.toggleActive : ''}`}
289→              onClick={() => editorDispatch({ type: 'TOGGLE_GRID' })}
290→              aria-label="Toggle Grid"
291→              title="Toggle Grid"
292→            >
293→              <svg viewBox="0 0 18 18" className={styles.icon}>
294→                <path d="M1 6h16M1 12h16M6 1v16M12 1v16" fill="none" stroke="currentColor" strokeWidth="1" />
295→              </svg>
