  5→import { SKETCH_TOOL_SHORTCUTS } from '../editor/tools';
  6→import { getViewLabel, viewToModelPosition } from '../domain/viewProjection';
  7→import { createSketchSelectHandler } from '../editor/handlers/selectHandler';
  8→import { createPartPlaceHandler } from '../editor/handlers/partPlaceHandler';
  9→import { createDimensionHandler } from '../editor/handlers/dimensionHandler';
 10→import CompassOverlay from '@/ui/CompassOverlay';
 11→import { CenterViewIcon, ExpandIcon, CollapseIcon } from '@/ui/ToolbarIcons';
 12→import GridRenderer from './GridRenderer';
