  1→import { useRef, useEffect, useCallback, useMemo, useState } from 'react';
  2→import * as THREE from 'three';
  3→import { useSketch } from '../app/SketchProvider';
  4→import { useSketchEditor } from '../app/SketchEditorProvider';
  5→import { buildSketchPreviewRoot } from './buildSketchPreview';
  6→import { getSketchPartInspection } from './sketchPreviewInspection';
  7→import { createPreviewViewport } from '@/three/viewer/createPreviewViewport';
  8→import { disposeScene } from '@/three/viewer/disposeScene';
  9→import CompassOverlay from '@/ui/CompassOverlay';
 10→import { ExpandIcon, CollapseIcon } from '@/ui/ToolbarIcons';
 11→import styles from './SketchPreviewPanel.module.css';
