 7→export default function SketchEmptyState() {
 8→  const { dispatch } = useSketch();
 9→  const { dispatch: editorDispatch } = useSketchEditor();
10→  const { setShowTemplateDialog } = useSketchProject();
11→
12→  const handleStartDrawing = () => {
13→    editorDispatch({ type: 'DISMISS_EMPTY_STATE' });
14→    editorDispatch({ type: 'SET_TOOL', tool: 'panel' });
15→  };
16→
17→  const handleDemoObject = () => {
18→    const { assembly, parts } = buildDemoTable();
19→
20→    for (const part of parts) {
21→      dispatch({ type: 'PART_ADD', part });
22→    }
23→    dispatch({ type: 'ASSEMBLY_ADD', assembly });
24→    editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: assembly.id });
25→    editorDispatch({ type: 'DISMISS_EMPTY_STATE' });
26→  };
27→
28→  return (
29→    <div className={styles.overlay}>
30→      <div className={styles.card}>
31→        <h2 className={styles.title}>Start designing</h2>
32→        <p className={styles.subtitle}>
33→          Assemble furniture from typed parts — panels, legs, frames — and view in orthographic drafting views
34→        </p>
35→        <div className={styles.actions}>
36→          <button className={styles.btnPrimary} onClick={handleStartDrawing}>
37→            Start Drawing
38→          </button>
39→          <button className={styles.btnSecondary} onClick={() => setShowTemplateDialog(true)}>
40→            Create from Template
41→          </button>
42→          <button className={styles.btnSecondary} onClick={handleDemoObject}>
43→            Try Demo Object
44→          </button>
45→        </div>
46→      </div>
47→    </div>
48→  );
49→}
